// ----------------------------------------------------------------------------
// SID Filter Cutoff Frequency Generator
//
// Extracted from sid_tables.sv. Contains only the filter cutoff frequency
// (F0) generation logic. All waveform lookup tables have been removed —
// waveforms are now generated by combinatorial AND logic in sid_voice.v.
//
// Based on the MOS 6581/8580 SID chip designed by Bob Yannes.
// Converted from SystemVerilog to Verilog-2001 for maximum FPGA portability.
//
// Bob Yannes on the filter cutoff:
//   "An 11-bit D/A converter generates the FET control voltage.
//    (It's actually a 12-bit D/A, but the LSB had no audible effect so
//    it was disconnected.)"
//
//   "The FET resistance varied considerably with processing, so different
//    lots of SID chips had different cutoff frequency characteristics."
//
// The MOS8580 uses a simple linear mapping: F0 = Fc * 5 (shifted).
// The MOS6581 uses a non-linear curve (f6581_curve) with tanh-like
// adjustment (f6581_adj) to model the FET voltage-controlled resistor
// behavior and chip-to-chip variation via Fc_offset.
// ----------------------------------------------------------------------------

module sid_cutoff
#(
	parameter MULTI_FILTERS   = 1
)
(
	input             clock,
	input             mode,

	// filter cutoff
	input       [1:0] cfg,
	input      [10:0] Fc,
	input      [12:0] Fc_offset,
	output     [15:0] F0,
	input             ld_clk,
	input      [11:0] ld_addr,
	input      [15:0] ld_data,
	input             ld_wr
);

// ----------------------------------------------------------------------------
// Filter cutoff frequency generation
//
// MOS8580 (mode=1): Linear mapping F0 = Fc*5 (simple shift and add).
// MOS6581 (mode=0): Non-linear curve via f6581_curve table + tanh adjustment.
//   - The curve models the FET voltage-controlled resistor behavior.
//   - f6581_adj provides tanh-like adjustment for chip-to-chip variation.
//   - Fc_offset calibrates individual chip cutoff characteristics.
//   - ld_clk/ld_addr/ld_data/ld_wr allow runtime loading of custom curves.
// ----------------------------------------------------------------------------

reg [15:0] f0;
generate
	if(MULTI_FILTERS) begin
		always @(posedge ld_clk) if(ld_wr) f6581_curve[1024+ld_addr] <= ld_data;
		always @(posedge clock) f0 <= f6581_curve[{cfg, Fc[10:1]}];
	end
	else begin
		always @(posedge ld_clk) if(ld_wr) f6581_curve[ld_addr[9:0]] <= ld_data;
		always @(posedge clock) f0 <= f6581_curve[Fc[10:1]];
	end
endgenerate

wire [10:0] fc_6581;
sid_dac #( .BITS(11) ) fc_dac
(
	.vin  (Fc),
	.vout (fc_6581)
);

function [9:0] tanh_x_mirror;
	input signed [10:0] x;
	begin
		tanh_x_mirror = x < 0 ? ~x[9:0] + 1'b1 : x[9:0];
	end
endfunction

function signed [10:0] tanh_x_clamp;
	input signed [12:0] x;
	begin
		if (x < -1023)
			tanh_x_clamp = -11'sd1023;
		else if (x > 1023)
			tanh_x_clamp = 11'sd1023;
		else
			tanh_x_clamp = x[10:0];
	end
endfunction

function signed [15:0] tanh_y_mirror;
	input x_neg;
	input signed [15:0] y;
	begin
		tanh_y_mirror = x_neg ? -y : y;
	end
endfunction

wire signed [15:0] f6581_adj_y0 = 16'sd10133;
wire [10:0] fc_x = tanh_x_clamp($signed({2'b0, fc_6581}) - $signed(Fc_offset));

reg [15:0] f0_adj;
always @(posedge clock) f0_adj <= {fc_x[10], f6581_adj[tanh_x_mirror(fc_x)]};

assign F0 = mode ? ({3'b000, Fc, 2'b00} + Fc) :
            Fc_offset ? (f6581_adj_y0 + tanh_y_mirror(f0_adj[15], f0_adj[14:0])) :
            {1'b0, f0[15:1]};

// value = pi * 1.048576 * f0[fc]
// NOTE: These large tables use SV array initialization syntax ('{...}).
// Most FPGA toolchains (Quartus, Vivado, Yosys with SystemVerilog support)
// accept this. If targeting a strict Verilog-2001 toolchain, convert to
// individual initial blocks. These tables are ROM and will be mapped to BRAM.
